CREATE TABLE "Event" (id TEXT PRIMARY KEY, tenantId TEXT NOT NULL, branchId TEXT, title TEXT NOT NULL, description TEXT, startDate TIMESTAMP NOT NULL, endDate TIMESTAMP, allDay BOOLEAN DEFAULT false, color TEXT, type TEXT DEFAULT 'GENERAL', isRecurring BOOLEAN DEFAULT false, recurrenceRule TEXT, createdById TEXT, createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updatedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP); CREATE INDEX Event_tenantId_idx ON "Event"(tenantId); CREATE INDEX Event_startDate_idx ON "Event"(startDate); CREATE TABLE "Holiday" (id TEXT PRIMARY KEY, tenantId TEXT NOT NULL, name TEXT NOT NULL, date TIMESTAMP NOT NULL, isRecurring BOOLEAN DEFAULT true, createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP); CREATE INDEX Holiday_tenantId_idx ON "Holiday"(tenantId);
